import{_ as a,c as i,o as t,ak as n,an as o}from"./chunks/framework.B95DSy-a.js";const g=JSON.parse('{"title":"AireGlu Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireglu-v1-114-0.md","filePath":"aireblock-releases/aireglu-v1-114-0.md","lastUpdated":1772645393000}'),r={name:"aireblock-releases/aireglu-v1-114-0.md"};function s(l,e,d,c,h,p){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="aireglu-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+o+'"> AireGlu Release Notes</span> <a class="header-anchor" href="#aireglu-release-notes" aria-label="Permalink to “AireGlu Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.114.0<br><strong>Release Date:</strong> February 26, 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>MCP Server Backend Support (GLU-2902)</li><li>Enhanced Authentication Security (GLU-2541)</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Saveless Endpoint Editor (GLU-2678, GLU-2679, GLU-2848)</li><li>Improved Endpoint Search and View Toggle (GLU-2868, GLU-2880)</li><li>Persistent Endpoint Search Text (GLU-2867)</li><li>Drag to Navigate on Node Page (GLU-2775)</li><li>Smarter Pagination Controls (GLU-2935)</li><li>Expanded Group View to Show All Endpoints (GLU-2936)</li><li>Improved Autoscaling Coverage (GLU-2883)</li><li>Reliable Export and Import for Internal Endpoints (GLU-2944)</li><li>SDK Updated to Release Version (GLU-2898)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Reduced Service Downtime from Cache Failures (GLU-2931)</li><li>Fixed Liquid and Token Evaluation in Endpoint Request Tasks (GLU-2947)</li><li>Fixed 404 Error When Saving New Endpoint Versions (GLU-2948)</li><li>Removed Deprecated Legacy Adapter Services (GLU-2969)</li><li>Fixed File Paths Being Cleared in Multipart Form Requests (GLU-2970)</li><li>Fixed Incorrect Row Removal in Multipart Form Editor (GLU-2974)</li></ul><h3 id="⚠️-upgrade-notes" tabindex="-1">⚠️ Upgrade Notes <a class="header-anchor" href="#⚠️-upgrade-notes" aria-label="Permalink to “⚠️ Upgrade Notes”">​</a></h3><hr><div class="warning custom-block"><p class="custom-block-title">includes BFF upgrade</p><p>This release contains an upgrade to BFF (Backend for Frontend) which is an automated workflow designed to transition web applications from client-side token management to server-side architecture using BFF. This upgrade may result in users being logged out of the AireGlu designer during the upgrade process. Users can simply log back in to the designer should this happen.</p></div><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="mcp-server-backend-support-glu-2902" tabindex="-1">MCP Server Backend Support (GLU-2902) <a class="header-anchor" href="#mcp-server-backend-support-glu-2902" aria-label="Permalink to “MCP Server Backend Support (GLU-2902)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>AireGlu can now act as an MCP server, allowing AI assistants and LLM-based tools to discover and invoke your AireGlu endpoints as tools or resources. This opens up the ability to connect AI applications directly to the integrations and workflows you have built in AireGlu, without additional middleware.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Implemented the backend infrastructure to expose AireGlu endpoints as a Model Context Protocol (MCP) server. Includes data models for MCP server configuration stored in MongoDB, a management API for defining which endpoints are available as MCP tools or resources, and a JSON-RPC 2.0 protocol handler integrated into the runtime service to route MCP tool calls to AireGlu endpoint execution.</p></div><h4 id="enhanced-authentication-security-glu-2541" tabindex="-1">Enhanced Authentication Security (GLU-2541) <a class="header-anchor" href="#enhanced-authentication-security-glu-2541" aria-label="Permalink to “Enhanced Authentication Security (GLU-2541)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Authentication is now handled more securely behind the scenes. Token management is no longer exposed to the browser, reducing the risk of token interception. You should not notice any change to your login experience, but your sessions will be better protected.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Implemented server-side authentication using the Duende BFF (Backend for Frontend) package, replacing the previous client-side token handling. Refresh tokens are now managed server-side. Local authentication is maintained for environments that require it, and the implementation aligns with the existing pattern adopted in AireFrame and AireIdentity.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="saveless-endpoint-editor-glu-2678-glu-2679-glu-2848" tabindex="-1">Saveless Endpoint Editor (GLU-2678, GLU-2679, GLU-2848) <a class="header-anchor" href="#saveless-endpoint-editor-glu-2678-glu-2679-glu-2848" aria-label="Permalink to “Saveless Endpoint Editor (GLU-2678, GLU-2679, GLU-2848)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You no longer need to remember to press Save when moving between tasks in the endpoint editor — your changes are kept automatically. If you want to discard what you have just done in the current task, use the &quot;Undo pending changes&quot; button. The × button in the top-right will close the dialog and discard any unsaved edits in the task currently open.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Reworked the save and cancel mechanism in the endpoint editor dialogs. Changes are now automatically validated and persisted to state when navigating between tasks or closing a task using the OK button. A dedicated &quot;Undo pending changes&quot; button replaces the previous cancel concept, and a close button (×) in the top-right discards any changes made in the currently open task. The undo action no longer closes the dialog.</p></div><h4 id="improved-endpoint-search-and-view-toggle-glu-2868-glu-2880" tabindex="-1">Improved Endpoint Search and View Toggle (GLU-2868, GLU-2880) <a class="header-anchor" href="#improved-endpoint-search-and-view-toggle-glu-2868-glu-2880" aria-label="Permalink to “Improved Endpoint Search and View Toggle (GLU-2868, GLU-2880)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Switching between the Endpoint and Group views is now quicker — one click instead of multiple. The search box is more intuitive, making it clear whether you are searching endpoints or groups based on which view you are in.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Moved the Endpoint/Group view toggle into the same toolbar as the search box, visually grouping view selection with search controls. The toggle is now a single-click control rather than a dropdown. The search box placeholder text updates to reflect the current view (&quot;Search endpoints…&quot; or &quot;Search groups…&quot;).</p></div><h4 id="persistent-endpoint-search-text-glu-2867" tabindex="-1">Persistent Endpoint Search Text (GLU-2867) <a class="header-anchor" href="#persistent-endpoint-search-text-glu-2867" aria-label="Permalink to “Persistent Endpoint Search Text (GLU-2867)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If you have filtered the endpoints list and refresh the page, your search text is retained. You no longer lose your search context after a page reload.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>The endpoint search query is now preserved in the URL, so it is restored automatically when the page is refreshed, consistent with behaviour in AireForms.</p></div><h4 id="drag-to-navigate-on-node-page-glu-2775" tabindex="-1">Drag to Navigate on Node Page (GLU-2775) <a class="header-anchor" href="#drag-to-navigate-on-node-page-glu-2775" aria-label="Permalink to “Drag to Navigate on Node Page (GLU-2775)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Navigating large or complex endpoint node diagrams is easier. Click and drag on any empty area of the canvas to move around, rather than relying on scroll bars alone.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Added click-and-drag functionality to the node page within the endpoint editor. Users can now click on the background canvas and drag to pan around the node layout.</p></div><h4 id="smarter-pagination-controls-glu-2935" tabindex="-1">Smarter Pagination Controls (GLU-2935) <a class="header-anchor" href="#smarter-pagination-controls-glu-2935" aria-label="Permalink to “Smarter Pagination Controls (GLU-2935)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>The Endpoints list and other views with fewer than 10 items will no longer show redundant pagination controls, making the interface cleaner and easier to use.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Pagination controls are now hidden when the number of items is fewer than 10, since paging is not applicable below that threshold. This applies throughout the application, including the Endpoints list where both group and endpoint paging were previously shown unnecessarily.</p></div><h4 id="expanded-group-view-to-show-all-endpoints-glu-2936" tabindex="-1">Expanded Group View to Show All Endpoints (GLU-2936) <a class="header-anchor" href="#expanded-group-view-to-show-all-endpoints-glu-2936" aria-label="Permalink to “Expanded Group View to Show All Endpoints (GLU-2936)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>When you expand a group in the Group view, all endpoints are visible without needing to page through them. This makes it faster to find and access endpoints within a group.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Pagination controls are now hidden when the number of items is fewer than 10, since paging is not applicable below that threshold. This applies throughout the application, including the Endpoints list where both group and endpoint paging were previously shown unnecessarily.</p></div><h4 id="improved-autoscaling-coverage-glu-2883" tabindex="-1">Improved Autoscaling Coverage (GLU-2883) <a class="header-anchor" href="#improved-autoscaling-coverage-glu-2883" aria-label="Permalink to “Improved Autoscaling Coverage (GLU-2883)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>More AireGlu services can now scale automatically under increased load, improving reliability and responsiveness during periods of high usage without manual intervention.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Autoscaling configuration has been extended to include additional services: the Repo Retriever service, Usage Data Writer, and XSLT Executor. Background services such as the email polling service, MESH polling service, and job runner have been intentionally excluded, along with services where throughput needs to remain limited.</p></div><h4 id="reliable-export-and-import-for-internal-endpoints-glu-2944" tabindex="-1">Reliable Export and Import for Internal Endpoints (GLU-2944) <a class="header-anchor" href="#reliable-export-and-import-for-internal-endpoints-glu-2944" aria-label="Permalink to “Reliable Export and Import for Internal Endpoints (GLU-2944)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Exporting an endpoint configuration from one environment (for example, production) and importing it into another (for example, development) will now correctly reference the target environment&#39;s endpoints, rather than carrying over references to the wrong environment.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>When exporting endpoints that invoke other AireGlu endpoints internally, the full endpoint URL (including host and environment) is no longer included in the export. Only the endpoint name is stored, and the correct host and environment are inferred at import time.</p></div><h4 id="sdk-updated-to-release-version-glu-2898" tabindex="-1">SDK Updated to Release Version (GLU-2898) <a class="header-anchor" href="#sdk-updated-to-release-version-glu-2898" aria-label="Permalink to “SDK Updated to Release Version (GLU-2898)”">​</a></h4><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>The stable SDK version is now in use, removing any uncertainty that might arise from running a pre-release dependency in a production environment.</p></div><div class="info custom-block"><p class="custom-block-title">Technical</p><p>Replaced the pre-release SDK with the stable release version. The pre-release version included a change to the data format that had no practical impact on adapter authoring but was present due to shared class placement.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="reduced-service-downtime-from-cache-failures-glu-2931" tabindex="-1">Reduced Service Downtime from Cache Failures (GLU-2931) <a class="header-anchor" href="#reduced-service-downtime-from-cache-failures-glu-2931" aria-label="Permalink to “Reduced Service Downtime from Cache Failures (GLU-2931)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Investigated and resolved an issue where a general failure to connect to Redis caused services to crash, despite Redis being configured as a non-critical dependency with a MongoDB fallback. The health check configuration has been corrected so that Redis connectivity issues no longer trigger service termination.</p></div><h4 id="fixed-liquid-and-token-evaluation-in-endpoint-request-tasks-glu-2947" tabindex="-1">Fixed Liquid and Token Evaluation in Endpoint Request Tasks (GLU-2947) <a class="header-anchor" href="#fixed-liquid-and-token-evaluation-in-endpoint-request-tasks-glu-2947" aria-label="Permalink to “Fixed Liquid and Token Evaluation in Endpoint Request Tasks (GLU-2947)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Resolved an issue where the AireGlu Endpoint Request task type was unable to evaluate Liquid templates or token expressions unless they were wrapped inside a string field. Non-string fields now correctly support Liquid and token evaluation.</p></div><h4 id="fixed-404-error-when-saving-new-endpoint-versions-glu-2948" tabindex="-1">Fixed 404 Error When Saving New Endpoint Versions (GLU-2948) <a class="header-anchor" href="#fixed-404-error-when-saving-new-endpoint-versions-glu-2948" aria-label="Permalink to “Fixed 404 Error When Saving New Endpoint Versions (GLU-2948)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Resolved a race condition where saving an endpoint using &quot;Save as new version&quot; or &quot;Add new version&quot; returned a 404 error immediately after saving. The endpoint was being saved correctly but was not yet available in time for the subsequent redirect, causing the error. Navigation now waits for the new version to be available before redirecting.</p></div><h4 id="removed-deprecated-legacy-adapter-services-glu-2969" tabindex="-1">Removed Deprecated Legacy Adapter Services (GLU-2969) <a class="header-anchor" href="#removed-deprecated-legacy-adapter-services-glu-2969" aria-label="Permalink to “Removed Deprecated Legacy Adapter Services (GLU-2969)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Removed legacy adapter service code that had been marked as deprecated and was no longer in use.</p></div><h4 id="fixed-file-paths-being-cleared-in-multipart-form-requests-glu-2970" tabindex="-1">Fixed File Paths Being Cleared in Multipart Form Requests (GLU-2970) <a class="header-anchor" href="#fixed-file-paths-being-cleared-in-multipart-form-requests-glu-2970" aria-label="Permalink to “Fixed File Paths Being Cleared in Multipart Form Requests (GLU-2970)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where file path values in HTTP Multipart Form Data request tasks were being cleared when the endpoint was saved.</p></div><h4 id="fixed-incorrect-row-removal-in-multipart-form-editor-glu-2974" tabindex="-1">Fixed Incorrect Row Removal in Multipart Form Editor (GLU-2974) <a class="header-anchor" href="#fixed-incorrect-row-removal-in-multipart-form-editor-glu-2974" aria-label="Permalink to “Fixed Incorrect Row Removal in Multipart Form Editor (GLU-2974)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a bug in the Multipart Form editor where removing a row was deleting or re-rendering the wrong row due to an indexing issue in the component.</p></div>',65)])])}const m=a(r,[["render",s]]);export{g as __pageData,m as default};
